import { createClient } from '@supabase/supabase-js'
import { NextResponse } from 'next/server'

export const dynamic = 'force-dynamic'

const COVER_B64 = ``

const CONTENT = `
<p>Todo mês de maio acontece a mesma coisa: quem trabalha com <strong>cestas de presente</strong> é soterrado por mensagens no WhatsApp perguntando "quais cestas você tem?", "qual o valor?", "tem foto?". Você responde uma por uma, repete os mesmos preços dez vezes por dia e, no meio da correria do <strong>Dia dos Namorados</strong>, ainda vende uma cesta que já tinha acabado o estoque.</p>

<p>Existe um jeito de acabar com isso — e ele não custa quase nada. A maioria das cesteiras ainda não descobriu, mas dá para montar um <strong>catálogo digital de cestas</strong>, organizado por estoque, que o cliente acessa sozinho, escolhe e já manda o pedido pronto no seu WhatsApp. É exatamente isso que vamos te ensinar a montar aqui.</p>

<h2>Por que o Dia dos Namorados é a sua maior oportunidade do ano</h2>
<p>O Dia dos Namorados é uma das datas que mais movimentam o comércio de presentes no Brasil — e a cesta personalizada é o queridinho do momento: café da manhã, cesta de chocolates, kit vinho e queijos, box romântico. O problema nunca é a falta de cliente. O problema é <strong>dar conta dos pedidos sem se perder</strong>.</p>
<p>Quem tem um catálogo organizado vende mais por um motivo simples: o cliente indeciso compra quando <em>vê</em> as opções com foto e preço. No vai-e-volta de mensagens, muita gente desiste. Um cardápio digital transforma a sua vitrine em algo que trabalha por você 24 horas por dia.</p>

<h2>Sim, dá para fazer cardápio de cestas no Cardápio Turbo</h2>
<p>O Cardápio Turbo nasceu para lanchonetes, mas a estrutura é perfeita para <strong>qualquer catálogo de produtos com foto, preço e pedido pelo WhatsApp</strong> — e isso inclui cestas. Em vez de "hambúrguer" e "porção", você cria categorias como "Cestas Românticas", "Cafés da Manhã" e "Kits Vinho". Cada cesta vira um produto com foto, descrição e valor.</p>
<p>E o melhor: você controla o que está disponível conforme o seu estoque, sem precisar avisar ninguém manualmente.</p>

<h2>Passo a passo: monte seu catálogo de cestas conforme o estoque</h2>

<h3>1. Crie sua conta e escolha o nome da sua loja</h3>
<p>Acesse <a href="https://cardapioturbo.com.br/register">cardapioturbo.com.br</a> e crie sua conta gratuitamente. Você tem 7 dias para testar tudo, sem cartão de crédito. No cadastro, dê o nome da sua marca de cestas e informe o número de WhatsApp que vai receber os pedidos.</p>

<h3>2. Monte as categorias por tipo de cesta</h3>
<p>Na aba <strong>Categorias</strong>, crie divisões claras para facilitar a escolha do cliente. Sugestões que funcionam para o Dia dos Namorados:</p>
<ul>
<li><strong>Cestas Românticas</strong> — as estrelas da data</li>
<li><strong>Cafés da Manhã Especiais</strong></li>
<li><strong>Kits Vinho & Chocolate</strong></li>
<li><strong>Cestas Premium</strong> (as de maior valor)</li>
<li><strong>Adicionais</strong> (balão, urso, cartão personalizado)</li>
</ul>

<h3>3. Cadastre cada cesta como um produto</h3>
<p>Na aba <strong>Produtos</strong>, adicione cada cesta com:</p>
<ul>
<li><strong>Foto real e bem iluminada</strong> — é o que mais vende. Mostre a cesta montada, não só os itens soltos.</li>
<li><strong>Nome chamativo</strong> — ex.: "Cesta Paixão", "Box Te Amo", "Café da Manhã do Casal".</li>
<li><strong>Descrição com o que vem dentro</strong> — liste os itens. O cliente adora saber exatamente o que está levando.</li>
<li><strong>Preço</strong> — deixe claro. Cesta sem preço espanta cliente.</li>
</ul>

<h3>4. Controle a disponibilidade conforme o estoque</h3>
<p>Aqui está o pulo do gato. Quando uma cesta esgota — ou quando você só consegue produzir um número limitado por dia —, basta <strong>desativar o produto</strong> ou marcá-lo como indisponível no painel. Ele some do catálogo na hora, e nenhum cliente vai pedir algo que você não tem. Quando repõe o estoque, reativa em um clique. Adeus, venda de cesta fantasma.</p>

<h3>5. Personalize as cores e gere seu QR Code e link</h3>
<p>Na aba <strong>Personalizar</strong>, ajuste as cores para o clima romântico da data (tons de vermelho e rosa caem bem). Depois, gere o <strong>link único</strong> e o <strong>QR Code</strong> do seu catálogo. Coloque o link na bio do Instagram, no status do WhatsApp e em todos os anúncios.</p>

<h3>6. Receba os pedidos prontos no WhatsApp</h3>
<p>Quando o cliente escolhe a cesta, ele preenche os dados e o pedido chega no seu WhatsApp já formatado: qual cesta, valor, nome de quem vai receber e mensagem do cartão. Você só confirma e produz. Sem mais "qual o valor mesmo?".</p>

<h2>3 dicas extras para vender mais cestas na data</h2>
<ul>
<li><strong>Crie cupons de desconto</strong> para pedidos antecipados — ex.: "AMOR10" para quem encomendar até dia 10. Isso organiza sua produção e evita o sufoco de última hora.</li>
<li><strong>Ofereça adicionais</strong> como categoria à parte (balão metalizado, ursinho, espumante). O cliente quase sempre incrementa o pedido.</li>
<li><strong>Mostre o prazo de entrega</strong> com clareza na descrição. Para o Dia dos Namorados, defina uma data limite de encomenda e comunique bem.</li>
</ul>

<h2>Comece hoje — antes do dia 12 chegar</h2>
<p>Faltando poucas semanas para o Dia dos Namorados, cada dia conta. Montar o catálogo leva alguns minutos e, depois disso, é a sua vitrine trabalhando sozinha enquanto você produz as cestas. Pare de responder preço no WhatsApp um por um e deixe o cliente escolher.</p>
<p><a href="https://cardapioturbo.com.br/register"><strong>Crie seu catálogo de cestas grátis no Cardápio Turbo</strong></a> e teste por 7 dias sem cartão. Seu Dia dos Namorados pode ser o mais organizado — e o mais lucrativo — de todos.</p>
`

export async function GET(req: Request) {
  const url = new URL(req.url)
  if (url.searchParams.get('secret') !== 'turbo-seed-2026') {
    return NextResponse.json({ error: 'unauthorized' }, { status: 401 })
  }
  const supabase = createClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.SUPABASE_SERVICE_ROLE_KEY!
  )

  const slug = 'catalogo-cestas-dia-dos-namorados'
  const buffer = Buffer.from(COVER_B64, 'base64')
  const path = `${slug}.png`
  await supabase.storage.from('blog').upload(path, buffer, { contentType: 'image/png', upsert: true })
  const { data: pub } = supabase.storage.from('blog').getPublicUrl(path)
  const coverUrl = pub.publicUrl

  await supabase.from('blog_posts').delete().eq('slug', slug)

  const { data, error } = await supabase.from('blog_posts').insert({
    title: 'Catálogo de cestas que vende sozinho: o passo a passo para o Dia dos Namorados',
    slug,
    excerpt: 'Quem mexe com cestas de presente pode montar um catálogo digital organizado por estoque e receber pedidos prontos no WhatsApp. Veja o passo a passo para o Dia dos Namorados.',
    content: CONTENT,
    category: 'Marketing',
    author: 'Equipe Cardápio Turbo',
    cover_emoji: '🧺',
    cover_image: coverUrl,
    read_minutes: 6,
    seo_title: 'Catálogo de cestas para o Dia dos Namorados: passo a passo no Cardápio Turbo',
    seo_description: 'Aprenda a montar um catálogo digital de cestas conforme o estoque e venda mais no Dia dos Namorados com pedidos direto no WhatsApp.',
    keywords: 'dia dos namorados, cesta de presente, catálogo de cestas, cardápio digital, cesta café da manhã',
    published: true,
    published_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
  }).select('slug').single()

  if (error) return NextResponse.json({ error: error.message }, { status: 500 })
  return NextResponse.json({ ok: true, slug: data.slug, coverUrl })
}
